@js:
// ========== 兜底svg配置区 ==========
var 默认封面配置 = {
	是否显示作者: true, // "true" 或 "false"
	排版方式: "横排", // "横排" 或 "竖排"
	最大行数: 3,
	每行最大字符: 10,
	作者最大字数: 10,
	作者可换行: false,
	背景颜色: "",
	文字颜色: "",
	作者颜色: "",
	字体大小: 28
};
try {
	默认封面配置.背景颜色 = "#" + String(java.getThemeConfigMap()["backgroundColor"]).match(/.{6}$/)[0];
	默认封面配置.文字颜色 = "#" + String(java.getThemeConfigMap()["accentColor"]).match(/.{6}$/)[0];
	默认封面配置.作者颜色 = "#" + String(java.getThemeConfigMap()["accentColor"]).match(/.{6}$/)[0];
} catch (e) {}
// 获取不到时使用默认值
默认封面配置.背景颜色 = 默认封面配置.背景颜色 || "#F0F8FF";
默认封面配置.文字颜色 = 默认封面配置.文字颜色 || "#333333";
默认封面配置.作者颜色 = 默认封面配置.作者颜色 || "#666666";

// ========== 搜索源 ==========
var channels = [
	{
		name: "起点",
		url: "https://m.qidian.com/so/书名.html",
		listRule: "class.y-list__item",
		authorSelector: "@css:*[class^=_searchBookAuthor]@text",
		authorReplace: {
			pattern: "作者\\s*",
			replacement: ""
		},
		coverSelector: "tag.a@tag.img@data-src",
		coverReplace: {
			pattern: "/\\d{3}$",
			replacement: ""
		},
		match: "exact"
	},
	{
		name: "晋江",
		url: "http://android.jjwxc.net/androidapi/search?keyword=书名",
		headers: {
			"User-Agent": String(java.getWebViewUA()).replace(/\/$/, '/') + "JINJIANG-Android"
		},
		listRule: "$.items[*]",
		authorSelector: "$.authorname",
		coverSelector: "$.cover",
		match: "exact"
	},
	{
		name: "长佩",
		url: "https://www.gongzicp.com/webapi/search/novels?k=书名",
		listRule: "$.data.list[*]",
		authorSelector: "$.novel_author",
		coverSelector: "$.novel_cover",
		coverReplace: {
			pattern: "\\?.*",
			replacement: ""
		},
		match: "exact"
	},
	{
		name: "纵横",
		url: "https://search.zongheng.com/search/book?keyword=书名&sort=&pageNo=1&pageNum=20&isFromHuayu=0",
		listRule: "$.data.datas.list[*]",
		authorSelector: "$.authorName",
		coverSelector: "$.coverUrl",
		coverReplace: {
			pattern: "^",
			replacement: "https://static.zongheng.com/upload/"
		},
		match: "exact"
	},
	{
		name: "推书君",
		url: "https://pre-api.tuishujun.com/api/searchBook?search_value=书名&page=1&pageSize=20",
		listRule: "$.data.data[*]",
		authorSelector: "$.author_nickname",
		coverSelector: "$.cover",
		bookTitleSelector: "$.title",
		match: "includes"
	},
	{
		name: "阅评说",
		url: "http://m.ypshuo.com/api/novel/search?keyword=书名&searchType=1&page=1",
		listRule: "$.data.data[*]",
		authorSelector: "$.author_name",
		coverSelector: "$.novel_img",
		bookTitleSelector: "$.novel_name",
		match: "includes"
	}
];
// ========== 工具函数 ==========
function applyRule(selector, replace) {
	if (!selector) return "";
	var prefix = /^\$|\/\/|@css|@json/i.test(selector) ? "" : "@@";
	var value = String(java.getString(prefix + selector));
	if (replace && replace.pattern) {
		var reg = new RegExp(replace.pattern, "g");
		value = value.replace(reg, replace.replacement || "");
	}
	return value;
}
function getCoverFromChannels(channels, book) {
	var bookName = book.name;
	var bookAuthor = book.author;
	for (var i = 0; i < channels.length; i++) {
		var ch = channels[i];
		var searchUrl = ch.url.replace(/书名/g, bookName);
		// 处理headers
		var ajaxUrl = searchUrl;
		if (ch.headers) {
			ajaxUrl = searchUrl + ",{headers:" + JSON.stringify(ch.headers) + "}";
		}
		var html = java.ajax(ajaxUrl);
		java.setContent(html);
		var listRulePrefix = /^\$|\/\/|@css|@json/i.test(ch.listRule) ? "" : "@@";
		var list = java.getElements(listRulePrefix + ch.listRule);
		for (var j in list) {
			java.setContent(list[j]);
			var author = applyRule(ch.authorSelector, ch.authorReplace).replace(/<\/font.*?>/gi, "");
			// 晋江特殊处理
			if (ch.name === "晋江" && author.match(/\*\*/)) {
				var author1 = author.replace(/\*{2,}.*/g, "");
				var author2 = author.replace(/.\*{2,}/, "");
				var areg = new RegExp("^" + author1);
				var areg2 = new RegExp(author2 + "$");
				if (author.match(areg) && author.match(areg2)) {
					return applyRule(ch.coverSelector, ch.coverReplace);
				}
			}
			if (ch.match === "includes") {
				var title = ch.bookTitleSelector ? applyRule(ch.bookTitleSelector) : "";
				var na = String(bookName),
					au = String(bookAuthor);
				var ti = String(title),
					au2 = String(author);
				var nameHit = !ch.bookTitleSelector || na.includes(ti) || ti.includes(na);
				var authorHit = au.includes(au2) || au2.includes(au);
				if (nameHit && authorHit) {
					return applyRule(ch.coverSelector, ch.coverReplace);
				}
			} else {
				if (author == bookAuthor) {
					return applyRule(ch.coverSelector, ch.coverReplace);
				}
			}
		}
	}
	return "";
}
// ========== svg封面 ==========
function 生成默认封面(书名, 作者, 配置) {
	if (!配置) 配置 = {};
	var 显示作者 = 配置.是否显示作者 !== false;
	var 排版方式 = 配置.排版方式 || "横排";
	var 最大行数 = 配置.最大行数 + 1;
	var 每行最大字符 = 配置.每行最大字符 || (排版方式 === "横排" ? 10 : 10);
	var 作者最大字数 = 配置.作者最大字数 || 10;
	var 作者可换行 = 配置.作者可换行 || false;
	var 背景颜色 = 配置.背景颜色 || "#F0F8FF";
	var 文字颜色 = 配置.文字颜色 || "#333333";
	var 作者颜色 = 配置.作者颜色 || "#666666";
	var 字体大小 = 配置.字体大小 || 28;
	var 实际宽度 = 300;
	var 实际高度 = 400;
	if (排版方式 === "横排") {
		let 处理横排书名 = (文本, 最大行数, 每行最大字符) => {
			if (!文本) return "";
			let 结果 = '',
				当前行 = '',
				最大总字数 = 每行最大字符 * 最大行数;
			for (let i = 0; i < Math.min(文本.length, 最大总字数); i++) {
				当前行 += 文本[i];
				if (当前行.length >= 每行最大字符 || i === Math.min(文本.length, 最大总字数) - 1) {
					let 当前行数 = 结果.split('\n').length;
					if (当前行数 < 最大行数 - 1) {
						结果 += 当前行;
						if (i < Math.min(文本.length, 最大总字数) - 1) 结果 += '\n';
						当前行 = '';
					} else {
						结果 += 当前行.substring(0, Math.max(1, 当前行.length - 1)) + '...';
						break;
					}
				}
			}
			return 结果 || 文本.substring(0, Math.min(文本.length, 每行最大字符));
		};
		let 处理横排作者 = (文本, 作者最大字数, 作者可换行) => {
			if (!文本) return "";
			if (文本.length <= 作者最大字数) return 文本;
			if (作者可换行) {
				let 每行字数 = Math.ceil(作者最大字数 / 2);
				let 结果 = '';
				for (let i = 0; i < 作者最大字数 && i < 文本.length; i++) {
					if (i > 0 && i % 每行字数 === 0) 结果 += '\n';
					结果 += 文本[i];
				}
				if (文本.length > 作者最大字数) 结果 = 结果.substring(0, 结果.length - 1) + '...';
				return 结果;
			}
			return 文本.substring(0, 作者最大字数 - 1) + '...';
		};
		let 书名文本 = 处理横排书名(书名, 最大行数, 每行最大字符);
		let 作者文本 = 显示作者 ? 处理横排作者(作者, 作者最大字数, 作者可换行) : "";
		let 书名行数 = 书名文本.includes('\n') ? 书名文本.split('\n').length : 1;
		let 行高 = 字体大小 * 1.4;
		let 作者字体大小 = 字体大小 * 0.8;
		let 作者行高 = 作者字体大小 * 1.3;
		let 书名区域高度 = 书名行数 * 行高;
		let 作者区域高度 = 显示作者 ? (作者文本.includes('\n') ? 作者文本.split('\n').length : 1) * 作者行高 : 0;
		let 总高度 = 书名区域高度 + 作者区域高度;
		let 顶部边距 = Math.max(50, (实际高度 - 总高度) / 2);
		let 书名SVG = 书名文本.split('\n').map((line, i) =>
			`<text text-anchor="middle" font-size="${字体大小}" fill="${文字颜色}" font-weight="bold" dy="${i * 行高}">${line}</text>`
		).join('');
		let 作者SVG = '';
		if (显示作者 && 作者文本) {
			作者SVG = 作者文本.split('\n').map((line, i) =>
				`<text text-anchor="middle" font-size="${作者字体大小}" fill="${作者颜色}" dy="${书名区域高度 + i * 作者行高 + 作者字体大小/2}">${line}</text>`
			).join('');
		}
		let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${实际宽度} ${实际高度}" width="${实际宽度}" height="${实际高度}">
            <rect width="${实际宽度}" height="${实际高度}" fill="${背景颜色}"/>
            <g transform="translate(${实际宽度/2}, ${顶部边距 + 行高/2})">
                ${书名SVG}
                ${作者SVG}
            </g>
        </svg>`;
		return "data:image/svg+xml;base64," + java.base64Encode(svg);
	} else { // 竖排
		let 处理竖排书名 = (文本, 最大行数, 每行最大字符) => {
			if (!文本) return "";
			let 最大总字数 = 每行最大字符 * 最大行数;
			let 显示文本 = 文本.substring(0, Math.min(文本.length, 最大总字数));
			if (文本.length > 最大总字数) 显示文本 = 显示文本.substring(0, 显示文本.length - 1) + '...';
			return 显示文本;
		};
		let 处理竖排作者 = (文本, 作者最大字数, 作者可换行) => {
			if (!文本) return "";
			if (文本.length <= 作者最大字数) return 文本;
			if (作者可换行) {
				let 每列字数 = Math.ceil(作者最大字数 / 2);
				let 结果 = '';
				for (let i = 0; i < 作者最大字数 && i < 文本.length; i++) {
					if (i > 0 && i % 每列字数 === 0) 结果 += '\n';
					结果 += 文本[i];
				}
				if (文本.length > 作者最大字数) 结果 = 结果.substring(0, 结果.length - 1) + '...';
				return 结果;
			}
			return 文本.substring(0, 作者最大字数 - 1) + '...';
		};
		let 书名文本 = 处理竖排书名(书名, 最大行数, 每行最大字符);
		let 作者文本 = 显示作者 ? 处理竖排作者(作者, 作者最大字数, 作者可换行) : "";
		let 字符数 = 书名文本.length;
		let 列间距 = 字体大小 * 0.2;
		let 行间距 = 字体大小 * 1.2;
		let 每列最大字数 = 每行最大字符; // 竖排时每列最大字数取配置的每行最大字符
		let 列数 = Math.min(最大行数, Math.ceil(字符数 / 每列最大字数));
		let 起始X = 字体大小;
		let 起始Y = 字体大小 + 20;
		let 书名元素 = '';
		for (let 列 = 0; 列 < 列数; 列++) {
			let 当前列X = 起始X + 列 * (字体大小 + 列间距);
			let 当前列起始字符 = 列 * 每列最大字数;
			let 当前列字数 = Math.min(每列最大字数, 字符数 - 当前列起始字符);
			for (let 行 = 0; 行 < 当前列字数; 行++) {
				let 字符索引 = 当前列起始字符 + 行;
				if (字符索引 >= 字符数) break;
				let 当前字符 = 书名文本[字符索引];
				let 当前Y = 起始Y + 行 * 行间距;
				书名元素 += `<text x="${当前列X + 字体大小/2}" y="${当前Y}" font-size="${字体大小}" fill="${文字颜色}" font-weight="bold" text-anchor="middle" dominant-baseline="middle">${当前字符}</text>`;
			}
		}
		let 作者元素 = '';
		if (显示作者 && 作者文本) {
			let 作者字体大小 = 字体大小 * 0.9;
			let 作者行间距 = 作者字体大小 * 1.2;
			if (作者可换行 && 作者文本.includes('\n')) {
				let 作者行数组 = 作者文本.split('\n');
				let 作者列数 = 作者行数组.length;
				for (let 列 = 0; 列 < 作者列数; 列++) {
					let 作者行 = 作者行数组[列];
					let 作者列X = 实际宽度 - 字体大小 - (作者列数 - 列 - 1) * 作者字体大小 * 1.5;
					let 作者区域高度 = 作者行.length * 作者行间距;
					let 作者起始Y = 实际高度 - 字体大小 - 作者区域高度;
					for (let 行 = 0; 行 < 作者行.length; 行++) {
						let 当前字符 = 作者行[行];
						let 当前Y = 作者起始Y + 行 * 作者行间距;
						作者元素 += `<text x="${作者列X}" y="${当前Y}" font-size="${作者字体大小}" fill="${作者颜色}" text-anchor="middle" dominant-baseline="middle">${当前字符}</text>`;
					}
				}
			} else {
				let 作者列X = 实际宽度 - 字体大小;
				let 作者区域高度 = 作者文本.length * 作者行间距;
				let 作者起始Y = 实际高度 - 字体大小 - 作者区域高度;
				for (let 行 = 0; 行 < 作者文本.length; 行++) {
					let 当前字符 = 作者文本[行];
					let 当前Y = 作者起始Y + 行 * 作者行间距;
					作者元素 += `<text x="${作者列X}" y="${当前Y}" font-size="${作者字体大小}" fill="${作者颜色}" text-anchor="middle" dominant-baseline="middle">${当前字符}</text>`;
				}
			}
		}
		let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${实际宽度} ${实际高度}" width="${实际宽度}" height="${实际高度}">
            <rect width="${实际宽度}" height="${实际高度}" fill="${背景颜色}"/>
            ${书名元素}
            ${作者元素}
        </svg>`;
		return "data:image/svg+xml;base64," + java.base64Encode(svg);
	}
}
// ========== 主流程 ==========
var 书名 = String(book.name).replace(/\s/g, '');
var 作者 = String(book.author).replace(/\s/g, '');
var cover = getCoverFromChannels(channels, book);
// 处理封面 URL（添加协议和 referer）
if (cover) {
	cover = /^\/\//.test(cover) ? "https:" + cover : cover;
	cover = cover.replace(/(https?:\/\/.*?)(\/.*)/, '$1$2,{"headers":{"referer":"$1"}}');
}
// 如果搜索无结果且原书也无封面，则使用svg封面
if (!cover && String(book.coverUrl) === "null") {
	cover = 生成默认封面(书名, 作者, 默认封面配置);
}
cover
